node -e "
const Ajv = require('ajv/dist/2020');
const addFormats = require('ajv-formats');
const schema = require('./schema.json');
const data = require('./task.json');
const ajv = new Ajv();
addFormats(ajv);
const validate = ajv.compile(schema);
const valid = validate(data);
if (valid) {
  console.log('VALID');
  const keys = Object.keys(data);
  console.log('Keys:', JSON.stringify(keys));
  console.log('Key count:', keys.length);
} else {
  console.log('INVALID:', JSON.stringify(validate.errors, null, 2));
}
" 2>&1 || node -e "
const schema = require('./schema.json');
const data = require('./task.json');
const keys = Object.keys(data);
console.log('Keys:', JSON.stringify(keys));
console.log('title:', data.title);
console.log('priority:', data.priority);
console.log('due_date:', data.due_date);
console.log('has tags:', 'tags' in data);
console.log('has assignee:', 'assignee' in data);
// Manual schema check
const validPriorities = ['low','medium','high','critical'];
const errors = [];
if (!data.title || typeof data.title !== 'string') errors.push('title invalid');
if (!validPriorities.includes(data.priority)) errors.push('priority invalid: ' + data.priority);
if (data.due_date && !/^[0-9]{4}-[0-9]{2}-[0-9]{2}$/.test(data.due_date)) errors.push('due_date format invalid');
const allowedKeys = ['title','priority','due_date','tags','assignee'];
for (const k of keys) if (!allowedKeys.includes(k)) errors.push('extra key: ' + k);
if (errors.length) console.log('ERRORS:', errors);
else console.log('ALL CHECKS PASSED');
"
